mapper.select:
SELECT lc.id, lc.case_no, lc.title_zh, lc.title_en, lc.case_reason, lc.case_type, lc.country, lc.court, lc.judgment_date, lc.summary_zh, lc.importance_score, lc.keywords, lc.source, lc.url, lc.ai_status, lc.fastgpt_sync_status, lc.fastgpt_synced_at, lc.view_count, lc.favorite_count, lc.created_at, lc.is_deleted, CASE WHEN uf.id IS NOT NULL THEN 1 ELSE 0 END AS is_favorited FROM legal_case lc LEFT JOIN user_favorite uf ON uf.case_id = lc.id AND uf.user_id = #{userId}
lc.is_deleted = 0 AND lc.ai_status = 2
AND MATCH(lc.title_zh, lc.title_en, lc.case_reason, lc.keywords, lc.summary_zh) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)
AND lc.case_type = #{caseType}
AND lc.country = #{country}
ORDER BY MATCH(lc.title_zh, lc.title_en, lc.case_reason, lc.keywords, lc.summary_zh) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE) DESC, lc.${orderBy} ${orderDir}
ORDER BY lc.${orderBy} ${orderDir}
